{!REQUIRESCRIPT("/soap/ajax/20.0/connection.js")}
var entuse = new sforce.SObject("Entitlement_Use__c"); 
entuse.id = "{!Entitlement_Use__c.Id}"; 
function checkError(result)
{
if (!result[0].getBoolean('success')) {
throw(result[0].errors.message);
}
}
try
{
var entuseData = sforce.connection.query("SELECT id,entitlement__r.Id,entitlement__r.Name,entitlement__r.Usage_Quantity__c,entitlement__r.Entitlement_Usage__c,entitlement__c from Entitlement_Use__c WHERE id ='{!Entitlement_Use__c.Id}' limit 1"); 
records = entuseData.getArray("records"); 

var ent = new sforce.SObject("Entitlement"); 
ent.id = records[0].entitlement__c; 
ent.Entitlement_Usage__c = null; 

resultofUpdate = sforce.connection.update([ent]); 
window.location.reload(); 

}
catch (err)
{
alert(err);
}
